final _tips = [
  {'id': 't001', 'title': 'Drink Water Before Meals', 'category': 'hydration', 'imageUrl': 'https://images.unsplash.com/photo-1548839140-29a749e1cf4d?w=800', 'content': 'Drinking 500ml of water 30 minutes before each meal can reduce calorie intake by up to 13% and aids digestion significantly.'},
  {'id': 't002', 'title': 'Eat Protein First', 'category': 'protein', 'imageUrl': 'https://images.unsplash.com/photo-1532550907401-a500c9a57435?w=800', 'content': 'Starting your meal with protein signals fullness faster, stabilizes blood sugar, and reduces overall calorie consumption throughout the day.'},
  {'id': 't003', 'title': 'The 80% Rule', 'category': 'mindful-eating', 'imageUrl': 'https://images.unsplash.com/photo-1490645935967-10de6ba17061?w=800', 'content': 'Eat until 80% full (Hara Hachi Bu). It takes 20 minutes for the stomach to signal fullness to the brain — stop before you feel stuffed.'},
  {'id': 't004', 'title': 'Color Your Plate', 'category': 'vegetables', 'imageUrl': 'https://images.unsplash.com/photo-1512003867696-6d5ce6835040?w=800', 'content': 'Aim for 5 different colored vegetables daily. Each color provides different phytonutrients and antioxidants essential for optimal health.'},
  {'id': 't005', 'title': 'Meal Prep Sundays', 'category': 'meal-planning', 'imageUrl': 'https://images.unsplash.com/photo-1547592180-85f173990554?w=800', 'content': 'Preparing meals in advance dramatically reduces fast food consumption and saves both money and time throughout the week.'},
  {'id': 't006', 'title': 'Healthy Fats Are Essential', 'category': 'fats', 'imageUrl': 'https://images.unsplash.com/photo-1474979266404-7eaacbcd87c5?w=800', 'content': 'Avocados, olive oil, nuts and fatty fish support brain function, hormone production and help absorb fat-soluble vitamins A, D, E, K.'},
  {'id': 't007', 'title': 'Fiber Keeps You Full', 'category': 'fiber', 'imageUrl': 'https://images.unsplash.com/photo-1563636619-e9143da7973b?w=800', 'content': 'Adults need 25-38g of fiber daily. Fiber slows digestion, feeds gut bacteria, and reduces the risk of heart disease and diabetes.'},
