  {'id': 't009', 'title': 'Limit Ultra-Processed Foods', 'category': 'education', 'imageUrl': 'https://images.unsplash.com/photo-1578916171728-46686eac8d58?w=800', 'content': 'Ultra-processed foods cause inflammation and are engineered to override satiety signals. Cook whole foods 80% of the time.'},
  {'id': 't010', 'title': 'Sleep Affects Weight', 'category': 'lifestyle', 'imageUrl': 'https://images.unsplash.com/photo-1541781774459-bb2af2f05b55?w=800', 'content': 'Poor sleep increases ghrelin (hunger hormone) by 15% and decreases leptin (fullness hormone). Aim for 7-9 hours nightly.'},
  {'id': 't011', 'title': 'Chew Slowly', 'category': 'mindful-eating', 'imageUrl': 'https://images.unsplash.com/photo-1490645935967-10de6ba17061?w=800', 'content': 'Chewing each bite 20-30 times improves digestion, reduces bloating, and helps you eat less by allowing fullness signals to register.'},
  {'id': 't012', 'title': 'Track Your Food', 'category': 'education', 'imageUrl': 'https://images.unsplash.com/photo-1467003909585-2f8a72700288?w=800', 'content': 'People who track food intake lose 50% more weight than those who do not. Awareness is the first step to better nutrition.'},
  {'id': 't013', 'title': 'Eat the Rainbow', 'category': 'vegetables', 'imageUrl': 'https://images.unsplash.com/photo-1512003867696-6d5ce6835040?w=800', 'content': 'Red, orange, yellow, green, blue and purple produce each contain unique compounds that fight disease and support immunity.'},
  {'id': 't014', 'title': 'Protein at Every Meal', 'category': 'protein', 'imageUrl': 'https://images.unsplash.com/photo-1532550907401-a500c9a57435?w=800', 'content': 'Aim for 20-30g of protein per meal to maintain muscle mass, boost metabolism and stay full between meals.'},
  {'id': 't015', 'title': 'Limit Liquid Calories', 'category': 'hydration', 'imageUrl': 'https://images.unsplash.com/photo-1548839140-29a749e1cf4d?w=800', 'content': 'Sodas, juices and alcohol add hundreds of hidden calories without satisfying hunger. Replace with water, herbal tea or black coffee.'},
  {'id': 't016', 'title': 'Time Your Carbs', 'category': 'carbohydrates', 'imageUrl': 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=800', 'content': 'Eat most of your carbohydrates around your workout — before for energy and after for glycogen replenishment and recovery.'},
