  {'id': 't018', 'title': 'Do Not Skip Breakfast', 'category': 'meal-planning', 'imageUrl': 'https://images.unsplash.com/photo-1488477181946-6428a0291777?w=800', 'content': 'A protein-rich breakfast reduces cravings, improves concentration and prevents overeating at lunch and dinner.'},
  {'id': 't019', 'title': 'Cook with Olive Oil', 'category': 'fats', 'imageUrl': 'https://images.unsplash.com/photo-1474979266404-7eaacbcd87c5?w=800', 'content': 'Extra virgin olive oil is rich in oleocanthal, a natural anti-inflammatory compound as potent as ibuprofen in some studies.'},
  {'id': 't020', 'title': 'Plan Before You Shop', 'category': 'meal-planning', 'imageUrl': 'https://images.unsplash.com/photo-1547592180-85f173990554?w=800', 'content': 'Shopping with a meal plan and a list reduces impulse buying of unhealthy foods and cuts grocery costs by up to 30%.'},
  {'id': 't021', 'title': 'Anti-Inflammatory Foods', 'category': 'immunity', 'imageUrl': 'https://images.unsplash.com/photo-1568702846914-96b305d2aaeb?w=800', 'content': 'Berries, fatty fish, broccoli, avocado and turmeric reduce chronic inflammation, the root cause of most modern diseases.'},
  {'id': 't022', 'title': 'Intermittent Fasting Basics', 'category': 'meal-planning', 'imageUrl': 'https://images.unsplash.com/photo-1490645935967-10de6ba17061?w=800', 'content': 'The 16:8 method (eat in an 8-hour window, fast 16 hours) can improve insulin sensitivity and support fat loss without calorie counting.'},
  {'id': 't023', 'title': 'Magnesium for Recovery', 'category': 'micronutrients', 'imageUrl': 'https://images.unsplash.com/photo-1563636619-e9143da7973b?w=800', 'content': 'Over 75% of people are magnesium deficient. Eat dark leafy greens, nuts, seeds and dark chocolate to support sleep, recovery and energy.'},
  {'id': 't024', 'title': 'Portion Plate Method', 'category': 'education', 'imageUrl': 'https://images.unsplash.com/photo-1490474418585-ba9bad8fd0ea?w=800', 'content': 'Fill half your plate with vegetables, one quarter with lean protein and one quarter with complex carbs for balanced nutrition every meal.'},
  {'id': 't025', 'title': 'Omega-3 for Brain Health', 'category': 'fats', 'imageUrl': 'https://images.unsplash.com/photo-1467003909585-2f8a72700288?w=800', 'content': 'Eat fatty fish 2-3 times per week or take a fish oil supplement. Omega-3s reduce depression risk, improve memory and fight inflammation.'},
  {'id': 't026', 'title': 'Never Eat in Front of Screens', 'category': 'mindful-eating', 'imageUrl': 'https://images.unsplash.com/photo-1490645935967-10de6ba17061?w=800', 'content': 'Distracted eating leads to consuming 25% more calories. Eating mindfully improves meal satisfaction and reduces overeating.'},
