  {'id': 't028', 'title': 'Stress Raises Cortisol', 'category': 'lifestyle', 'imageUrl': 'https://images.unsplash.com/photo-1541781774459-bb2af2f05b55?w=800', 'content': 'Chronic stress raises cortisol which drives fat storage in the abdomen. Meditation, walking and breathing exercises lower cortisol naturally.'},
